var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그러니까…","JPN":"だから……","ENG":"So...","TWN":"所以…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"유일한 재산으로 갖고 다니던 화분의 흙 속에서, 그 칼을 발견했단 말이지?","JPN":"唯一の財産として持ち歩いていた植木鉢の土の中から、そのナイフを見つけたのだな？","ENG":"You found that knife in the dirt of the pot you were carrying around as your only property?","TWN":"你是在你唯一的財產，也就是那個花盆裡發現這把刀的？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"그리고 그 화분은 소냐가 처음 고아원에 들어갈 때부터 함께 맡겨진 물건이었고요!","JPN":"そして、その植木鉢はソーニャが孤児院に預けられる時から一緒に預けられた物でしたね！","ENG":"And you had that pot even when you first entered the orphanage!","TWN":"然後這個花盆從你去孤兒院時，就一直陪伴著你！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Right.","TWN":"嗯。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아마 그 사람은 검을 일부러 화분에 넣어뒀을 거야.","JPN":"たぶんあの人はわざと刀を植木鉢に入れたんだ。","ENG":"I think he put the knife in the pot on purpose.","TWN":"這把刀應該是他特意放進花盆裡的。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"제아무리 무법자가 많은 프론트베이라도, 꼬마애를 상대로 화분을 훔쳐가는 도둑은 없을 테니까.","JPN":"いくら無法者だらけのフロントベイでも、子どもを相手に植木鉢を奪っていく泥棒はないはずだから。","ENG":"Even with all those criminals around, nobody would steal a flower pot from a child.","TWN":"畢竟就算前灣的歹徒再怎麼多，也不至於去偷一個小孩的花盆。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"헉, 그럼 소냐는 아버지가 남긴 유일한 유산으로 생선을 썰고 있었던 거네요?!","JPN":"へえ、じゃあソーニャはお父さんが残してくれた唯一の遺産で魚をさばいていたんですね！？","ENG":"*Gasp.* Then Sonya, you were slicing fish with the only inheritance your father left you?!","TWN":"嚇！所以你拿爸爸留給你唯一的遺產去殺魚嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"역시 해적! 해적스러움을 넘어선 초월적인 패륜!","JPN":"さすが海賊！　海賊らしさを越えた超越的な親不孝！","ENG":"So piratey! You've transcended pirateness! It's just downright disrespectful!","TWN":"不愧是海盜！簡直超越海盜的倫理道德！"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"자기 아빠 재산이 실린 배를 턴 애가 할 소린 아닌 것 같은데.","JPN":"自分のパパの財産がある船を盗んだ人が言う言葉ではないと思うけど。","ENG":"Says the girl who robbed the ship with her father's wealth.","TWN":"你這個偷走自己父親財產的人沒資格說我吧？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"그 칼에 새겨진 표식은 대해적 에이버리의 심볼이야. 알고 있었나?","JPN":"そのナイフに刻まれている印は大海賊エイバリーのシンボルだ。知っていたか？","ENG":"That symbol on the knife is the symbol of Great Pirate Avery. Were you aware?","TWN":"你知道刀上刻的記號是大海盜艾維利的標誌嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"워낙 유명하니까.","JPN":"まぁ、有名だからな。","ENG":"Yeah, since he's famous and all.","TWN":"嗯，因為它很有名。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"대해적에게 자식이 있었단 얘긴 처음 듣는데.","JPN":"大海賊に子どもがいたという話は初めて聞くけど。","ENG":"I didn't know the Great Pirate had a kid.","TWN":"我從來沒聽說過大海盜有孩子。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"여태 아무에게도 말하지 않은 건가?","JPN":"今まで誰にも言わなかったのか？","ENG":"Have you kept it a secret so far?","TWN":"你沒告訴過其他人嗎？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"관심 없어.","JPN":"興味ない。","ENG":"I don't really care.","TWN":"沒興趣"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"해적 핏줄인 게 자랑도 아니고, 애초에 날 키워준 건 얼굴도 모르는 아버지가 아니라 고아원이었으니까.","JPN":"親が海賊なのが別に自慢でもないし、そもそもあたしを育ててくれたのは顔も知らないお父さんではなく、孤児院だったから。","ENG":"It's not a good thing to be a descendant of a pirate. Plus, the orphanage raised me, not my father.","TWN":"我沒有對自己的海盜血統感到驕傲，當初養育我的也不是那不露面的父親，而是孤兒院。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"그 사람에게 난… 있으나 없으나 아무래도 좋은 존재였을 거야.","JPN":"あの人にあたしは……別にいてもいなくてもいい存在だったんだ。","ENG":"To him... I was probably a nobody.","TWN":"對那個人來說，我…不過是可有可無的存在。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"CANNON_SHARKS_NULL_NULL","text":{"KOREA":"소냐….","JPN":"ソーニャ……","ENG":"Sonya...","TWN":"索妮雅…"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"CANNON_SHARKS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"볼일이 끝났으니, 이 섬에 더 머물 이유는 없겠군.","JPN":"用は終わったから、これ以上この島にとどまる必要はない。","ENG":"Well, since we're done here, we should get going.","TWN":"既然事情都辦完了，也就沒必要再留在這座島上。"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"JACK_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_NULL","text":{"KOREA":"아가씨들이 타고 온 배는 어디에 있지?","JPN":"お嬢さんたちが乗っていた船はどこだ？","ENG":"Where's the ship you brought?","TWN":"小丫頭，你們的船在哪裡？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DAGGER_SHARKS_NULL_NULL","text":{"KOREA":"아, 그거 말이지.","JPN":"あ、それなんだけど。","ENG":"Oh, that.","TWN":"我們船喔？"},"stage":{"bg":"FOREST_NORMAL_02","slots":{"L":null,"C":{"char_id":"DAGGER_SHARKS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};